3	declare(strict_types=1);
4	
5	namespace VeloCMS\Modules\Translation\Services;
6	
7	use VeloCMS\Core\Services\TranslationService;
8	use VeloCMS\Modules\Translation\Models\GlossaryModel;
9	use VeloCMS\Modules\Translation\Models\TranslationModel;
10	
11	class TranslationEngine
12	{
13	    private TranslationModel $model;
14	    private GlossaryModel $glossary;
15	    private TranslationService $service;
16	    private string $defaultLang;
17	    /** @var string[] */
18	    private array $targetLangs;
19	
20	    public function __construct()
21	    {
22	        $this->model   = new TranslationModel();
23	        $this->glossary = new GlossaryModel();
24	        $this->service = new TranslationService();
25	
26	        $activeLangs       = json_decode(setting('active_languages', '["de","en"]'), true) ?: ['de', 'en'];
27	        $this->defaultLang = setting('default_language', 'de');
28	        $this->targetLangs = array_values(array_filter(
29	            $activeLangs,
30	            fn(string $l) => $l !== $this->defaultLang
31	        ));
32	    }
33	
34	    /**
35	     * Translate all UI strings from lang/en.php into every active non-default language
36	     * that has no static lang/{lang}.php file. Results are cached in velocms_translations
37	     * with table_name='velocms_ui' and row_id=0.
38	     */
39	    public function translateUiStrings(): void
40	    {
41	        $enPath = BASE_PATH . '/lang/en.php';
42	        if (!file_exists($enPath)) {
43	            return;
44	        }
45	
46	        $strings = require $enPath;
47	        if (!is_array($strings)) {
48	            return;
49	        }
50	
51	        foreach ($this->targetLangs as $lang) {
52	            if (file_exists(BASE_PATH . "/lang/{$lang}.php")) {
53	                continue;
54	            }
55	            try {
56	                $this->translateUiIntoLang($strings, $lang);
57	            } catch (\Throwable $e) {
58	                error_log('[TranslationEngine] UI lang=' . $lang . ': ' . $e->getMessage());
59	            }
60	        }
61	    }
62	
63	    /** @param array<string,string> $strings */
64	    private function translateUiIntoLang(array $strings, string $lang): void
65	    {
66	        $pending     = [];
67	        $pendingKeys = [];
68	
69	        foreach ($strings as $key => $text) {
70	            if (!is_string($key) || !is_string($text) || trim($text) === '') {
71	                continue;
72	            }
73	
74	            $existing = $this->model->get('velocms_ui', 0, $key, $lang);
75	            if ($existing && $existing['source'] === 'manual') {
76	                continue;
77	            }
78	
79	            $hash = md5($text);
80	            if ($existing && $existing['content_hash'] === $hash) {
81	                continue;
82	            }
83	
84	            $pending[]     = $text;
85	            $pendingKeys[] = [$key, $hash];
86	        }
87	
88	        if (empty($pending)) {
89	            return;
90	        }
91	
92	        // Translate in chunks of 50 to stay within API limits
93	        foreach (array_chunk($pending, 50) as $ci => $chunk) {
94	            $keyChunk   = array_slice($pendingKeys, $ci * 50, 50);
95	            $translated = $this->service->translateBatch($chunk, strtoupper($lang), 'EN');
96	
97	            foreach ($keyChunk as $i => [$key, $hash]) {
98	                $this->model->upsert('velocms_ui', 0, $key, $lang, $translated[$i], 'auto', $hash);
99	            }
100	        }
101	    }
102	
103	    /**
104	     * Translate all given fields for a DB row into every active non-default language.
105	     *
106	     * @param string            $table  DB table name (e.g. 'velocms_blog_posts')
107	     * @param int               $rowId  Primary key of the row
108	     * @param array<string,string> $fields field => source-text map
109	     */
110	    public function translateRow(string $table, int $rowId, array $fields, bool $force = false): void
111	    {
112	        foreach ($this->targetLangs as $lang) {
113	            try {
114	                $this->translateRowIntoLang($table, $rowId, $fields, $lang, $force);
115	            } catch (\Throwable $e) {
116	                error_log('[TranslationEngine] lang=' . $lang . ' table=' . $table
117	                    . ' id=' . $rowId . ': ' . $e->getMessage());
118	            }
119	        }
120	    }
121	
122	    /** @param array<string,string> $fields */
123	    private function translateRowIntoLang(string $table, int $rowId, array $fields, string $lang, bool $force = false): void
124	    {
125	        $pending     = [];
126	        $pendingKeys = [];
127	
128	        foreach ($fields as $field => $text) {
129	            if (trim($text) === '') {
130	                continue;
131	            }
132	
133	            $existing = $this->model->get($table, $rowId, $field, $lang);
134	            $hash     = md5($text);
135	
136	            if (!$force && $existing && $existing['content_hash'] === $hash) {
137	                continue;
138	            }
139	
140	            $pending[]     = $text;
141	            $pendingKeys[] = [$field, $hash];
142	        }
143	
144	        if (empty($pending)) {
145	            return;
146	        }
147	
148	        // Apply glossary: replace protected terms with placeholders before translating
149	        $placeholderMaps = [];
150	        foreach ($pending as $i => $text) {
151	            [$pending[$i], $placeholderMaps[$i]] = $this->applyGlossary($text, $this->defaultLang, $lang);
152	        }
153	
154	        $translated = $this->service->translateBatch(
155	            $pending,
156	            strtoupper($lang),
157	            strtoupper($this->defaultLang)
158	        );
159	
160	        foreach ($pendingKeys as $i => [$field, $hash]) {
161	            $result = $this->restoreGlossary($translated[$i], $placeholderMaps[$i]);
162	            $this->model->upsert($table, $rowId, $field, $lang, $result, 'auto', $hash);
163	        }
164	    }
165	
166	    /**
167	     * Replace glossary source terms with numeric placeholders.
168	     *
169	     * @return array{0: string, 1: array<string,string>}
170	     */
171	    private function applyGlossary(string $text, string $sourceLang, string $targetLang): array
172	    {
173	        $terms = $this->glossary->getAll($sourceLang, $targetLang);
174	        if (empty($terms)) {
175	            return [$text, []];
176	        }
177	
178	        $map = [];
179	        foreach ($terms as $i => $term) {
180	            $placeholder = '[[VCMS_' . $i . ']]';
181	            $pattern     = '/(?<![a-zA-Z0-9])' . preg_quote($term['source_term'], '/') . '(?![a-zA-Z0-9])/u';
182	            if (preg_match($pattern, $text)) {
183	                $text    = preg_replace($pattern, $placeholder, $text) ?? $text;
184	                $map[$placeholder] = $term['target_term'];
185	            }
186	        }
187	
188	        return [$text, $map];
189	    }
190	
191	    /** Restore glossary target terms from placeholders. */
192	    private function restoreGlossary(string $text, array $map): string
193	    {
194	        if (empty($map)) {
195	            return $text;
196	        }
197	        return str_replace(array_keys($map), array_values($map), $text);
198	    }
199	}
