35	
36	    public function dashboard(): void
37	    {
38	        $stats = [];
39	        foreach ($this->targetLangs as $lang) {
40	            $stats[$lang] = $this->model->getStats($lang);
41	        }
42	
43	        $this->render('admin/translation/dashboard', [
44	            'stats'       => $stats,
45	            'targetLangs' => $this->targetLangs,
46	            'defaultLang' => $this->defaultLang,
47	        ]);
