49	
50	    public function editor(): void
51	    {
52	        $lang    = $this->sanitizeLang($this->input('lang', $this->targetLangs[0] ?? 'en'));
53	        $table   = (string) $this->input('table', '');
54	        $source  = (string) $this->input('source', '');
55	        $editId  = (int) $this->input('edit', 0);
56	        $page    = max(1, (int) $this->input('page', 1));
57	        $perPage = 25;
58	        $offset  = ($page - 1) * $perPage;
59	
60	        $rows   = $this->model->getList($lang, $table, $source, $perPage, $offset);
61	        $total  = $this->model->countList($lang, $table, $source);
62	        $tables = $this->model->getTables();
63	        $pages  = (int) ceil($total / $perPage);
64	
65	        $editRow = $editId > 0 ? $this->model->getById($editId) : null;
66	
67	        $this->render('admin/translation/editor', [
68	            'rows'        => $rows,
69	            'total'       => $total,
70	            'page'        => $page,
71	            'pages'       => $pages,
72	            'perPage'     => $perPage,
73	            'tables'      => $tables,
74	            'targetLangs' => $this->targetLangs,
75	            'lang'        => $lang,
76	            'table'       => $table,
77	            'source'      => $source,
78	            'editRow'     => $editRow,
79	            'editId'      => $editId,
80	        ]);
81	    }
82	
83	    public function saveTranslation(string $id): void
84	    {
85	        Auth::verifyCsrf();
86	        $row = $this->model->getById((int) $id);
87	        if (!$row) {
88	            $this->redirectWithError('/admin/apps/translation/editor', t('error.not_found'));
89	        }
90	        $this->model->updateManual((int) $id, (string) $this->input('value', ''));
91	        $qs = $this->buildEditorQs($row['language'], $row['table_name']);
92	        $this->redirectWithSuccess('/admin/apps/translation/editor?' . $qs, t('success.saved'));
