98	        $row = $this->model->getById((int) $id);
99	        if (!$row) {
100	            $this->redirectWithError('/admin/apps/translation/editor', t('error.not_found'));
101	        }
102	        $this->model->unlock((int) $id);
103	        $qs = $this->buildEditorQs($row['language'], $row['table_name']);
104	        $this->redirectWithSuccess('/admin/apps/translation/editor?' . $qs, t('translation.action_unlock'));
105	    }
106	
107	    public function settings(): void
108	    {
109	        $this->render('admin/translation/settings', [
110	            'activeLangs'  => $this->activeLangs,
111	            'defaultLang'  => $this->defaultLang,
112	            'provider'     => setting('translation_provider', 'deepl'),
113	            'deeplKey'     => setting('deepl_api_key', ''),
114	            'anthropicKey' => setting('anthropic_api_key', ''),
115	        ]);
116	    }
117	
118	    public function saveSettings(): void
119	    {
120	        Auth::verifyCsrf();
121	
122	        $knownLangs = [
123	            'ar','bg','cs','da','de','el','en','es','et','fi','fr',
124	            'hu','id','it','ja','ko','lt','lv','nb','nl','pl',
125	            'pt','ro','ru','sk','sl','sr','sv','tr','uk','zh',
126	        ];
127	        $selected   = array_filter(
128	            (array) ($_POST['active_languages'] ?? []),
129	            fn(string $l) => in_array($l, $knownLangs, true)
130	        );
131	        if (empty($selected)) {
132	            $this->redirectWithError('/admin/apps/translation/settings', t('error.required'));
133	        }
134	        $selected = array_values($selected);
135	
136	        $default = trim((string) $this->input('default_language', 'de'));
137	        if (!in_array($default, $selected, true)) {
138	            $default = $selected[0];
139	        }
140	
141	        $provider = $this->input('translation_provider', 'deepl');
142	        if (!in_array($provider, ['deepl', 'anthropic'], true)) {
143	            $provider = 'deepl';
144	        }
145	
146	        $this->saveSetting('active_languages', json_encode($selected));
147	        $this->saveSetting('default_language', $default);
148	        $this->saveSetting('translation_provider', $provider);
149	
150	        $deeplKey = trim((string) $this->input('deepl_api_key', ''));
151	        if ($deeplKey !== '') {
152	            $this->saveSetting('deepl_api_key', $deeplKey);
153	        }
154	
155	        $anthropicKey = trim((string) $this->input('anthropic_api_key', ''));
156	        if ($anthropicKey !== '') {
157	            $this->saveSetting('anthropic_api_key', $anthropicKey);
158	        }
159	
160	        $engine = new \VeloCMS\Modules\Translation\Services\TranslationEngine();
161	        $this->redirectWithSuccessAndBackground(
162	            '/admin/apps/translation/settings',
163	            t('translation.settings_saved'),
164	            fn() => $engine->translateUiStrings()
165	        );
166	    }
167	
168	    public function export(): void
169	    {
170	        $db   = Database::getInstance()->getPdo();
171	        $rows = $db->query(
172	            'SELECT table_name, row_id, field, language, value, source
173	             FROM velocms_translations ORDER BY table_name, row_id, field, language'
174	        )->fetchAll(\PDO::FETCH_ASSOC);
175	
176	        header('Content-Type: text/csv; charset=utf-8');
177	        header('Content-Disposition: attachment; filename="translations-' . date('Y-m-d') . '.csv"');
178	        header('Cache-Control: no-cache');
179	
180	        $out = fopen('php://output', 'w');
181	        fputcsv($out, ['table_name', 'row_id', 'field', 'language', 'value', 'source']);
182	        foreach ($rows as $row) {
183	            fputcsv($out, [
184	                $row['table_name'],
185	                $row['row_id'],
186	                $row['field'],
187	                $row['language'],
188	                $row['value'],
189	                $row['source'],
190	            ]);
191	        }
192	        fclose($out);
193	        exit;
194	    }
195	
196	    public function import(): void
197	    {
198	        Auth::verifyCsrf();
199	
200	        $file = $_FILES['csv_file'] ?? null;
201	        if (!$file || $file['error'] !== UPLOAD_ERR_OK) {
202	            $this->redirectWithError('/admin/apps/translation/settings', t('translation.import_error'));
203	        }
204	
205	        $handle = fopen($file['tmp_name'], 'r');
206	        if ($handle === false) {
207	            $this->redirectWithError('/admin/apps/translation/settings', t('translation.import_error'));
208	        }
209	
210	        $header  = fgetcsv($handle);
211	        $allowed = ['table_name', 'row_id', 'field', 'language', 'value', 'source'];
212	        if ($header !== $allowed) {
213	            fclose($handle);
214	            $this->redirectWithError('/admin/apps/translation/settings', t('translation.import_error'));
215	        }
216	
217	        $count      = 0;
218	        $transModel = new TranslationModel();
219	        while (($cols = fgetcsv($handle)) !== false) {
220	            if (count($cols) < 5) {
221	                continue;
222	            }
223	            [$table, $rowId, $field, $lang, $value] = $cols;
224	            $source = $cols[5] ?? 'manual';
225	
226	            if (!preg_match('/^[a-z][a-z0-9_]*$/', $table)) {
227	                continue;
228	            }
229	            if (!preg_match('/^[a-z]{2}$/', $lang)) {
230	                continue;
231	            }
232	            if (!in_array($source, ['auto', 'manual'], true)) {
233	                $source = 'manual';
234	            }
235	
236	            $transModel->upsert($table, (int) $rowId, $field, $lang, $value, $source, md5($value));
237	            $count++;
238	        }
239	        fclose($handle);
240	
241	        $this->redirectWithSuccess(
242	            '/admin/apps/translation/settings',
243	            sprintf(t('translation.import_success'), $count)
244	        );
245	    }
246	
247	    private function saveSetting(string $key, string $value): void
248	    {
249	        $db   = Database::getInstance()->getPdo();
250	        $stmt = $db->prepare(
251	            'INSERT INTO velocms_settings (`key`, value) VALUES (:k, :v)
252	             ON DUPLICATE KEY UPDATE value = :v2'
253	        );
254	        $stmt->execute([':k' => $key, ':v' => $value, ':v2' => $value]);
255	    }
256	
257	    private function sanitizeLang(string $lang): string
258	    {
259	        return in_array($lang, $this->targetLangs, true) ? $lang : ($this->targetLangs[0] ?? 'en');
260	    }
261	
262	    private function buildEditorQs(string $lang, string $table): string
263	    {
264	        return http_build_query(['lang' => $lang, 'table' => $table]);
265	    }
